var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"도플갱어 신드롬이군.","JPN":"ドッペルゲンガーシンドロームね。","ENG":"Sounds like the Doppelganger Syndrome.","TWN":"是二重身症候群。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"카운터와 일반인을 가리지 않고, 본체가 살아 있더라도 발생하는 그림자 특이체......","JPN":"カウンター、一般人を問わずに本体が生きていても発生するシャドウ特異体……","ENG":"These unorthodox Shadows are exact copies of humans, Counters or not. And they can be generated even if their original counterparts are alive.","TWN":"不限制裁者或是普通人，即使本體活著，也會發生的暗影特異體……"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"녀석들이라면 함선의 동결을 풀기 위해 뭐든 하려 들겠지.","JPN":"連中なら、艦船の凍結を解除するために何でもするはずよ。","ENG":"They'd probably do anything to unlock the stasis.","TWN":"他們會不擇手段地解除艦船的凍結。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"본래 그림자들과 다르게 원본을 흡수해야만 완전해질 수 있으니까.","JPN":"通常のシャドウと違ってオリジナルを吸収しなければ完全になれないのだから。","ENG":"Unlike conventional Shadows, those Doppelgangers have to absorb the original copy to become whole.","TWN":"和原本的暗影不同，他們必須吸收本體才能變得完整。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"맞아. 내 생각도 같다.","JPN":"ああ。私も同意見だ。","ENG":"That's right. I suspect the same.","TWN":"對，我也是這麼想。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서, 그 뒤엔 어떻게 됐지?","JPN":"それで、その後はどうなったの？","ENG":"So what happened next?","TWN":"所以呢，後來怎麼樣了？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"간신히 놈들의 추격망에서 벗어나 떠돌다가 한 무리의 용병들을 만났지.","JPN":"何とか奴らの追撃を逃れて流れ着いた先で、ある傭兵集団に出会った。","ENG":"I barely lost them and wandered about until I met a group of mercenaries.","TWN":"我好不容易擺脫他們的追擊，後來在流浪的時候遇到了一群傭兵。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"CARGO_SL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RIFLE_SL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"처음엔 관리국의 생존자들인 줄 알았는데, 못 보던 장비로 이터니움을 채굴하고 있더군.","JPN":"最初は管理局の生存者たちかと思ったが、\\n見慣れない装備でエタニウムの採掘を行っていてな。","ENG":"At first I thought they were survivors from the Administration, until I saw them mining for Eternium with equipment I had never seen before.","TWN":"一開始我以為他們是管理局的倖存者，結果卻看到他們在用陌生的設備採集永恆之金。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그들의 도움으로 돌아오는 데 성공했다.","JPN":"彼らの協力を得て、帰還することに成功したのだ。","ENG":"They helped me come back here.","TWN":"然後我就在他們的幫助之下，成功返回了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 현실 세계는...... 기억 속의 모습과 많이 달라져 있었어.","JPN":"しかし現実世界は……記憶の中の風景とはすっかり変わっていた。","ENG":"But this Normalside... It's a lot different from how I remembered it.","TWN":"但現實世界……已經遠遠不是我記憶中的樣子了。"},"stage":{"bg":"PROLOGUE_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"내가 알던 관리국은 사라지고, 이면세계와 카운터의 존재까지 세상에 알려졌다니......","JPN":"私の知る管理局は消え失せ、裏世界とカウンターの存在までも\\n世間に知れ渡るとは……","ENG":"The Administration as I knew it is no more, and even the lay public is aware of the existence of the Counterside and Counters...","TWN":"我所知道的管理局不但消失了，就連異界和制裁者的存在為世人所知。"},"stage":{"bg":"PROLOGUE_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"처음에는 정말 나유빈의 말처럼 다른 세계로 넘어온 줄 알았다.","JPN":"最初はイチノセの言う通り、本当に別世界に来たのかと思ったくらいだ。","ENG":"At first, I thought we had reached a parallel world as Yubin suggested.","TWN":"一開始我還真的以為就像羅瑜斌所說，來到了另一個世界。"},"stage":{"bg":"PROLOGUE_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 조금 더 조사해 보니, 그저 시간이 흘렀을 뿐이었어.","JPN":"しかし調査した結果、ただ時間が経ったにすぎないことがわかった。","ENG":"But when I looked into it a little more, it turns out that time had just passed by.","TWN":"但再稍微調查了一下，才發現只是時間流逝了而已。"},"stage":{"bg":"SKYLINE_NIGHT2","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"생각보다...... 아주 많이.","JPN":"想定よりも遥かに……長い時間がな。","ENG":"A lot more... than I thought.","TWN":"流逝得……很多。"},"stage":{"bg":"SKYLINE_NIGHT2","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"내 연락처는 어떻게 안 거지?","JPN":"どうやって私の連絡先を知ったの？","ENG":"How did you find my contact info?","TWN":"妳是怎麼知道我的連絡方式的？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};